import React, { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import "./StudentPage.css";

interface Assignment {
    assid: number;
    asstitle: string;
    description: string;
    createdat: string; // Data va veni ca string
    fileUrl: string;
}

export default function StudentPage() {
    const [assignments, setAssignments] = useState<Assignment[]>([]);
    const navigate = useNavigate();
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        const token = localStorage.getItem("token");
        axios
            .get<Assignment[]>("http://localhost:9090/api/assignments", {
                headers: { Authorization: `Bearer ${token}` },
            })
            .then((res) => setAssignments(res.data))
            .catch((err) => console.error("Eroare la preluarea temelor:", err));
    }, []);

    return (
        <div className="student-page">
            <h2>Temele disponibile</h2>
            <table className="assignment-table">
                <thead>
                <tr>
                    <th>Titlu</th>
                    <th>Profesor</th>
                    <th>Data</th>
                </tr>
                </thead>
                <tbody>
                {assignments.map((a) => (
                    <tr
                        key={a.id}
                        onClick={() => navigate(`/assignment/${a.id}`)}
                        className="clickable-row"
                    >
                        <td>{a.asstitle}</td>
                        <td>{a.postedBy}</td>
                        <td>{new Date(a.datePosted).toLocaleDateString()}</td>
                    </tr>
                ))}
                </tbody>
            </table>
        </div>
    );
}
